parameters.jsCode:
const input = $input.first().json.chatInput || "";
const urlRegex = /(https?:\/\/[^\s,]+)/gi;
const matches = input.match(urlRegex) || [];

const xmlUrls = matches.filter(url => /\.xml$/i.test(url));

if (xmlUrls.length === 0) {
  return [{ json: { error: "No valid sitemap URLs found. Please provide at least one URL ending in .xml." } }];
}

if (xmlUrls.length > 10) {
  return [{ json: { error: `You provided ${xmlUrls.length} URLs. Please limit your request to a maximum of 10 sitemap URLs.` } }];
}

return xmlUrls.map(url => ({
  json: { url }
}));

const items = $input.all();

return items.map(item => ({
  json: {
    url: item.json.url,
    sourceUrl: item.json.url
  }
}));

const successItems = $input.all();
const originalItems = $('Cache Validated URLs').all();

return successItems.map((item, index) => ({
  json: {
    url: originalItems[index]?.json?.sourceUrl || originalItems[index]?.json?.url || 'Unknown URL',
    statusCode: item.json.statusCode || 200
  }
}));

