parameters.jsCode:
const allUrls = [];
let hasIndex = false;

for (const item of $input.all()) {
  const data = item.json;
  if ($input.first().json.sitemapindex) {
    hasIndex = true;
    break;
  }
  if (data.urlset && data.urlset.url) {
    let urls = Array.isArray(data.urlset.url) ? data.urlset.url : [data.urlset.url];
    allUrls.push(...urls);
  }
}

if (hasIndex) {
  return [{ json: { isIndex: true, error: "The following URLs are sitemap index files:" } }];
}

return [{ json: { isIndex: false, urls: allUrls, totalCount: allUrls.length } }];

